spec.inputArgumentsSchemaV2:
{
        "type": "object",
        "required": [],
        "properties": {
          "in_CaseId": {
            "type": "string",
            "description": "Maestro Case ID passed from the Maestro Case context. Used as the Storage Bucket folder name for attachments. If empty, the Gmail message ID is used as the folder name."
          }
        }
      }

spec.outputArgumentsSchemaV2:
{
        "type": "object",
        "properties": {
          "out_SalesforceOrderId": {
            "type": "string",
            "description": "Salesforce Order record ID created from the shipment email"
          },
          "out_CaseId": {
            "type": "string",
            "description": "Case ID = Salesforce Order.OrderNumber, used as Storage Bucket key"
          },
          "out_PO_HasAllDetails": {
            "type": "boolean",
            "description": "True if all 22 CBP-required shipment fields were extracted from the email"
          },
          "out_MissingFields": {
            "type": "string",
            "description": "JSON array of missing field names when out_PO_HasAllDetails is false"
          },
          "out_AttachmentCount": {
            "type": "integer",
            "description": "Number of attachments found on the email"
          },
          "out_HasEmail": {
            "type": "boolean",
            "description": "True if an unread shipment email was found in the INBOX"
          }
        }
      }

